"use client";

import { useCallback, useEffect, useRef, useState } from "react";
import { AnimatePresence, motion } from "motion/react";

const carouselImages = [
  "/images/voice-api.webp",
  "/images/imagine-api.webp",
  "/images/collections-api.webp",
  "/images/fast-api.webp",
];

const INTERVAL_MS = 4000;
const DOT_SIZE = 6;
const RING_SIZE = 16;
const STROKE_WIDTH = 1.5;
const RADIUS = (RING_SIZE - STROKE_WIDTH) / 2;
const CIRCUMFERENCE = 2 * Math.PI * RADIUS;

export function HeroSectionV6Carousel() {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [resetKey, setResetKey] = useState(0);
  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const advance = useCallback(() => {
    setCurrentIndex((prev) => (prev + 1) % carouselImages.length);
    setResetKey((k) => k + 1);
  }, []);

  const goTo = useCallback((index: number) => {
    setCurrentIndex(index);
    setResetKey((k) => k + 1);
  }, []);

  useEffect(() => {
    timerRef.current = setInterval(advance, INTERVAL_MS);
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [advance, resetKey]);

  return (
    <div className="hs6-carousel rounded-xl border border-border bg-card overflow-hidden shadow-xl">
      <AnimatePresence mode="popLayout">
        <motion.div
          key={currentIndex}
          initial={{ opacity: 0, scale: 1.02 }}
          animate={{ opacity: 1, scale: 1 }}
          exit={{ opacity: 0, scale: 0.98 }}
          transition={{ duration: 0.4, ease: [0.16, 1, 0.3, 1] }}
          className="hs6-carousel-slide"
          style={{ backgroundImage: `url(${carouselImages[currentIndex]})` }}
          role="img"
          aria-label={`Product preview ${currentIndex + 1}`}
        />
      </AnimatePresence>

      <div className="hs6-carousel-indicators">
        <div className="hs6-dots-backdrop">
          {carouselImages.map((_, index) => {
            const isActive = index === currentIndex;
            return (
              <button
                key={index}
                onClick={() => goTo(index)}
                className="hs6-dot-wrapper"
                aria-label={`Go to slide ${index + 1}`}
              >
                {isActive && (
                  <svg
                    className="hs6-dot-ring"
                    width={RING_SIZE}
                    height={RING_SIZE}
                    viewBox={`0 0 ${RING_SIZE} ${RING_SIZE}`}
                  >
                    <circle
                      cx={RING_SIZE / 2}
                      cy={RING_SIZE / 2}
                      r={RADIUS}
                      fill="none"
                      stroke="rgba(255,255,255,0.2)"
                      strokeWidth={STROKE_WIDTH}
                    />
                    <motion.circle
                      key={resetKey}
                      cx={RING_SIZE / 2}
                      cy={RING_SIZE / 2}
                      r={RADIUS}
                      fill="none"
                      stroke="rgba(255,255,255,0.9)"
                      strokeWidth={STROKE_WIDTH}
                      strokeLinecap="round"
                      strokeDasharray={CIRCUMFERENCE}
                      initial={{ strokeDashoffset: CIRCUMFERENCE }}
                      animate={{ strokeDashoffset: 0 }}
                      transition={{
                        duration: INTERVAL_MS / 1000,
                        ease: "linear",
                      }}
                      style={{
                        transformOrigin: "center",
                        transform: "rotate(-90deg)",
                      }}
                    />
                  </svg>
                )}

                <motion.span
                  className="hs6-dot-core"
                  animate={{
                    scale: isActive ? 1 : 0.7,
                    opacity: isActive ? 1 : 0.4,
                  }}
                  whileHover={{ scale: isActive ? 1 : 0.9, opacity: 0.8 }}
                  transition={{ type: "spring", stiffness: 400, damping: 25 }}
                  style={{
                    width: DOT_SIZE,
                    height: DOT_SIZE,
                  }}
                />
              </button>
            );
          })}
        </div>
      </div>
    </div>
  );
}

const stats = [
  { value: "10,000+", label: "Active users each month" },
  { value: "50%", label: "Reduction in support tickets" },
  { value: "2x", label: "Increase in feature adoption" },
  { value: "99.99%", label: "Service uptime" },
];

export function HeroSectionV6Stats() {
  return (
    <div className="mt-8">
      <div className="grid grid-cols-2 gap-3 sm:gap-4">
        {stats.map((stat) => (
          <div
            key={stat.label}
            className="rounded-lg border border-border/70 bg-background/80 px-4 py-3 text-left shadow-sm backdrop-blur-sm dark:border-border/60 dark:bg-background/40"
          >
            <p className="text-xl font-semibold tracking-tight text-foreground sm:text-2xl">
              {stat.value}
            </p>
            <p className="mt-1 text-xs text-muted-foreground sm:text-sm">{stat.label}</p>
          </div>
        ))}
      </div>
    </div>
  );
}

import * as React from "react"
import { Slot } from "@radix-ui/react-slot"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "./utils"

const buttonVariants = cva(
  "inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-md text-sm font-medium transition-all disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg:not([class*='size-'])]:size-4 shrink-0 [&_svg]:shrink-0 outline-none focus-visible:border-ring focus-visible:ring-ring/50 focus-visible:ring-[3px] aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 aria-invalid:border-destructive",
  {
    variants: {
      variant: {
        default: "bg-primary text-primary-foreground hover:bg-primary/90",
        destructive:
          "bg-destructive text-white hover:bg-destructive/90 focus-visible:ring-destructive/20 dark:focus-visible:ring-destructive/40 dark:bg-destructive/60",
        outline:
          "border bg-background shadow-xs hover:bg-accent hover:text-accent-foreground dark:bg-input/30 dark:border-input dark:hover:bg-input/50",
        secondary:
          "bg-secondary text-secondary-foreground hover:bg-secondary/80",
        ghost:
          "hover:bg-accent hover:text-accent-foreground dark:hover:bg-accent/50",
        link: "text-primary underline-offset-4 hover:underline",
      },
      size: {
        default: "h-9 px-4 py-2 has-[>svg]:px-3",
        sm: "h-8 rounded-md gap-1.5 px-3 has-[>svg]:px-2.5",
        lg: "h-10 rounded-md px-6 has-[>svg]:px-4",
        icon: "size-9",
        "icon-sm": "size-8",
        "icon-lg": "size-10",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  }
)

function Button({
  className,
  variant,
  size,
  asChild = false,
  ...props
}: React.ComponentProps<"button"> &
  VariantProps<typeof buttonVariants> & {
    asChild?: boolean
  }) {
  const Comp = asChild ? Slot : "button"

  return (
    <Comp
      data-slot="button"
      className={cn(buttonVariants({ variant, size, className }))}
      {...props}
    />
  )
}

export { Button, buttonVariants }

import { clsx, type ClassValue } from "clsx"
import { twMerge } from "tailwind-merge"

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs))
}

/* Hero Section V6 */

.hs6-hero {
  position: relative;
  overflow: hidden;
  isolation: isolate;
}

.hs6-bg-pattern {
  display: none;
}

.hs6-carousel {
  position: relative;
  width: 100%;
  aspect-ratio: 4 / 3;
  min-height: clamp(300px, 36vw, 520px);
  overflow: hidden;
}

.hs6-carousel-slide {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  background-size: cover;
  background-position: center;
  will-change: opacity, transform;
}

.hs6-carousel-indicators {
  position: absolute;
  bottom: 14px;
  left: 50%;
  transform: translateX(-50%);
  z-index: 10;
}

.hs6-dots-backdrop {
  display: flex;
  align-items: center;
  gap: 4px;
  padding: 4px 8px;
  border-radius: 999px;
  background: rgba(0, 0, 0, 0.25);
  backdrop-filter: blur(8px);
  -webkit-backdrop-filter: blur(8px);
}

.hs6-dot-wrapper {
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
  width: 16px;
  height: 16px;
  border: none;
  background: none;
  cursor: pointer;
  padding: 0;
}

.hs6-dot-ring {
  position: absolute;
  inset: 0;
}

.hs6-dot-core {
  display: block;
  border-radius: 50%;
  background-color: rgba(255, 255, 255, 0.95);
}
